import requests, datetime

PROMETHEUS_URL = "http://prometheus:9090"

def get_tenant_ingest_cost(month: str) -> list[dict]:
    """
    Estimate monthly observability cost per tenant using ingest volume.
    Costs are approximate: $0.15/GB for Loki, $0.20/M spans for Tempo.
    """
    # Loki ingest by team label (bytes ingested via Loki distributor metrics)
    loki_resp = requests.get(f"{PROMETHEUS_URL}/api/v1/query", params={
        "query": (
            f'sum by (team) ('
            f'  increase(loki_distributor_bytes_received_total{{}}[30d])'
            f') / 1e9'  # convert to GB
        )
    }).json()

    # Tempo ingest by team (spans received)
    tempo_resp = requests.get(f"{PROMETHEUS_URL}/api/v1/query", params={
        "query": (
            f'sum by (team) ('
            f'  increase(tempo_distributor_spans_received_total{{}}[30d])'
            f') / 1e6'  # convert to millions
        )
    }).json()

    loki_costs = {r["metric"]["team"]: float(r["value"][1]) * 0.15
                  for r in loki_resp["data"]["result"]}
    tempo_costs = {r["metric"]["team"]: float(r["value"][1]) * 0.20
                   for r in tempo_resp["data"]["result"]}

    all_teams = set(loki_costs) | set(tempo_costs)
    return sorted([
        {
            "team": team,
            "loki_cost_usd": round(loki_costs.get(team, 0), 2),
            "tempo_cost_usd": round(tempo_costs.get(team, 0), 2),
            "total_usd": round(loki_costs.get(team, 0) + tempo_costs.get(team, 0), 2),
        }
        for team in all_teams
    ], key=lambda x: -x["total_usd"])

if __name__ == "__main__":
    costs = get_tenant_ingest_cost("2024-08")
    print(f"{'Team':<30} {'Loki':>10} {'Tempo':>10} {'Total':>10}")
    print("-" * 62)
    for c in costs:
        print(f"{c['team']:<30} ${c['loki_cost_usd']:>9.2f} ${c['tempo_cost_usd']:>9.2f} ${c['total_usd']:>9.2f}")
